const stdout = $json.stdout || '';
const stderr = $json.stderr || '';

const failCount = (stdout.match(/\[FAIL\]/g) || []).length;
const warnCount = (stdout.match(/\[WARN\]/g) || []).length;
const okCount   = (stdout.match(/\[OK\]/g)   || []).length;

const zipMatch = stdout.match(/Archive: (.+\.zip)/);
const zipFile  = zipMatch ? zipMatch[1].trim() : 'لم يُنشأ ملف مضغوط';

const success = (failCount === 0) && (okCount > 0);

return [{ json: {
  success: success,
  verdict: success
    ? ('نجح: ' + okCount + ' مكون' + (warnCount > 0 ? ' (' + warnCount + ' تحذير)' : '') + ' | الملف: ' + zipFile)
    : ('فشل: ' + failCount + ' مكون فشل | ' + zipFile),
  ok_count:   okCount,
  warn_count: warnCount,
  fail_count: failCount,
  zip_file:   zipFile,
  raw_output: stdout.substring(0, 1000)
}}];
